//! Replay of frozen websocket client core vectors generated by an
//! in-package dump test at release-v2.1.5: 19 scenarios whose steps
//! share one client so the transaction filter carries across calls.
//! Covered: the session id result, rescans over real mainnet block
//! 432,100 discovering transactions by address (regular and ticket
//! outputs) and by outpoint (including a vote found through its
//! ticket outpoint with the stakebase input skipped, and the
//! treasury-active coinbase whose inputs are checked because the
//! old-style coinbase no longer classifies as one), incremental
//! filter loading, the rescan error ladder, the loadtxfilter
//! outpoint decode error, all notification registrations, the
//! rebroadcastwinners walk, the websocket help variant, and the
//! fallback to the standard dispatch.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use dcroxide_chaincfg::mainnet_params;
use dcroxide_chainhash::Hash;
use dcroxide_dcrjson::{GoValue, Registry, gojson, parse_params};
use dcroxide_rpc::helpers::NoInterfaces;
use dcroxide_rpc::server::{Config, RpcBestState, RpcChain, RpcSubsidyParams, Server};
use dcroxide_rpc::websocket::{RpcNtfnManager, WsClient, ws_cmd_result};
use dcroxide_rpctypes::{method, register_all};
use dcroxide_standalone::SubsidyCache;
use dcroxide_wire::{MsgBlock, PROTOCOL_VERSION};

const VECTORS: &str = include_str!("data/rpchandlers14_vectors.txt");

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

fn utf8(hex: &str) -> String {
    String::from_utf8(unhex(hex)).unwrap()
}

/// Split a JSON array into the raw JSON text of its elements.
fn split_json_array(data: &str) -> Vec<String> {
    let bytes = data.as_bytes();
    assert_eq!(bytes.first(), Some(&b'['), "params must be an array");
    let mut elems = Vec::new();
    let mut depth = 0i32;
    let mut in_string = false;
    let mut escaped = false;
    let mut start = None;
    for (i, &b) in bytes.iter().enumerate() {
        if in_string {
            if escaped {
                escaped = false;
            } else if b == b'\\' {
                escaped = true;
            } else if b == b'"' {
                in_string = false;
            }
            continue;
        }
        match b {
            b'"' => {
                in_string = true;
                if start.is_none() {
                    start = Some(i);
                }
            }
            b'[' | b'{' => {
                if depth > 0 && start.is_none() {
                    start = Some(i);
                }
                depth += 1;
            }
            b']' | b'}' => {
                depth -= 1;
                if depth == 0 {
                    if let Some(s) = start {
                        elems.push(data[s..i].trim().to_string());
                    }
                    break;
                }
            }
            b',' if depth == 1 => {
                if let Some(s) = start {
                    elems.push(data[s..i].trim().to_string());
                }
                start = None;
            }
            b' ' | b'\t' | b'\n' | b'\r' => {}
            _ => {
                if depth == 1 && start.is_none() {
                    start = Some(i);
                }
            }
        }
    }
    elems
}

/// The scripted chain over real block 432,100 (the default dcrd mock
/// chain reports the treasury agenda as active).
struct MockChain14 {
    block: MsgBlock,
    block_by_hash: Result<(), String>,
    tip_generation: Vec<Hash>,
    lottery: Vec<Hash>,
}

impl RpcChain for MockChain14 {
    fn best_snapshot(&mut self) -> RpcBestState {
        RpcBestState {
            hash: self.block.header.block_hash(),
            prev_hash: self.block.header.prev_block,
            height: 432100,
            bits: self.block.header.bits,
            next_stake_diff: 14428162590,
            total_subsidy: 1122503888072909,
            block_size: u64::from(self.block.header.size),
            num_txns: 7,
        }
    }
    fn block_by_hash(&mut self, _hash: &Hash) -> Result<MsgBlock, String> {
        self.block_by_hash.clone().map(|()| self.block.clone())
    }
    fn is_treasury_agenda_active(&mut self, _prev_blk_hash: &Hash) -> Result<bool, String> {
        Ok(true)
    }
    fn tip_generation(&mut self) -> Vec<Hash> {
        self.tip_generation.clone()
    }
    fn lottery_data_for_block(&mut self, _hash: &Hash) -> Result<Vec<Hash>, String> {
        Ok(self.lottery.clone())
    }
    fn best_header(&mut self) -> (Hash, i64) {
        (Hash([0u8; 32]), 432100)
    }
}

/// A no-op notification manager mirroring dcrd's test stub.
struct NoopNtfnMgr;

impl RpcNtfnManager for NoopNtfnMgr {
    fn register_block_updates(&mut self, _session_id: u64) {}
    fn unregister_block_updates(&mut self, _session_id: u64) {}
    fn register_work_updates(&mut self, _session_id: u64) {}
    fn unregister_work_updates(&mut self, _session_id: u64) {}
    fn register_tspend_updates(&mut self, _session_id: u64) {}
    fn unregister_tspend_updates(&mut self, _session_id: u64) {}
    fn register_winning_tickets(&mut self, _session_id: u64) {}
    fn register_new_tickets(&mut self, _session_id: u64) {}
    fn register_new_mempool_txs_updates(&mut self, _session_id: u64) {}
    fn unregister_new_mempool_txs_updates(&mut self, _session_id: u64) {}
    fn register_mix_messages(&mut self, _session_id: u64) {}
    fn unregister_mix_messages(&mut self, _session_id: u64) {}
    fn notify_winning_tickets(&mut self, _hash: &Hash, _height: i64, _tickets: &[Hash]) {}
}

#[test]
fn websocket_client_core_matches_dcrd() {
    let params = mainnet_params();
    let mut registry = Registry::new();
    register_all(&mut registry);

    let block: MsgBlock = include_str!("data/rpchandlers8_vectors.txt")
        .lines()
        .find_map(|line| {
            let f: Vec<&str> = line.split('|').collect();
            (f[0] == "blk").then(|| MsgBlock::from_bytes(&unhex(f[1])).unwrap().0)
        })
        .expect("block fixture");
    let ticket_hash = block.stransactions[4].tx_hash();

    let lines: Vec<&str> = VECTORS
        .lines()
        .filter(|l| l.starts_with("wscen|") || l.starts_with("wstep|") || l.starts_with("wsres|"))
        .collect();
    let mut scenarios = 0;
    let mut i = 0;
    while i < lines.len() {
        let scen: Vec<&str> = lines[i].split('|').collect();
        assert_eq!(scen[0], "wscen");
        i += 1;
        scenarios += 1;

        let name = scen[2];
        let tip_generation: usize = scen[3].parse().unwrap();
        let block_by_hash = match scen[4].strip_prefix("ERR:") {
            Some(err) => Err(err.to_string()),
            None => Ok(()),
        };

        let chain = MockChain14 {
            block: block.clone(),
            block_by_hash,
            tip_generation: vec![block.header.block_hash(); tip_generation],
            lottery: if tip_generation > 0 {
                vec![ticket_hash]
            } else {
                Vec::new()
            },
        };
        let mut server = Server::new(Config {
            chain,
            chain_params: params.clone(),
            subsidy_cache: SubsidyCache::new(RpcSubsidyParams(params.clone())),
            min_relay_tx_fee: 10000,
            max_protocol_version: PROTOCOL_VERSION,
            sync_mgr: Box::new(()),
            conn_mgr: Box::new(()),
            tx_mempooler: Box::new(()),
            clock: Box::new(()),
            interfaces: Box::new(NoInterfaces),
            rand_u64: Box::new(|| 0),
            tx_indexer: None,
            db: Box::new(()),
            filterer_v2: Box::new(()),
            exists_addresser: None,
            log_manager: Box::new(()),
            fee_estimator: Box::new(()),
            block_templater: None,
            sanity_checker: Box::new(()),
            time_source: Box::new(()),
            proxy: String::new(),
            test_net: false,
            runtime_version: String::new(),
            cpu_miner: Box::new(()),
            mix_pooler: Box::new(()),
            profiler_mgr: Box::new(()),
            addr_manager: Box::new(()),
            mining_addrs: Vec::new(),
            user_agent_version: String::new(),
            net_info: Vec::new(),
            services: 0,
            request_shutdown: Box::new(|| {}),
            allow_unsynced_mining: false,
            rpc_user: String::new(),
            rpc_pass: String::new(),
            rpc_limit_user: String::new(),
            rpc_limit_pass: String::new(),
        });
        server.ntfn_mgr = Box::new(NoopNtfnMgr);
        let mut wsc = WsClient::new(4660);

        while i < lines.len() && lines[i].starts_with("wstep|") {
            let step: Vec<&str> = lines[i].split('|').collect();
            let result: Vec<&str> = lines[i + 1].split('|').collect();
            assert_eq!(step[0], "wstep");
            assert_eq!(result[0], "wsres");
            i += 2;

            let step_name = step[3];
            let method_name = step[4];
            let params_json = utf8(step[5]);
            let raw_params = split_json_array(&params_json);
            let param_refs: Vec<&str> = raw_params.iter().map(|s| s.as_str()).collect();
            let cmd_instance = parse_params(&registry, &method(method_name), &param_refs)
                .unwrap_or_else(|e| panic!("{name}/{step_name}: parse params: {e:?}"));
            let cmd = GoValue::Struct(cmd_instance.fields);

            match ws_cmd_result(&mut server, &mut wsc, method_name, &cmd) {
                Ok((value, typ)) => {
                    assert_eq!(result[3], "ok", "{name}/{step_name}: expected an error");
                    let got = gojson::encode(&typ, &value);
                    assert_eq!(got, utf8(result[4]), "{name}/{step_name}: result");
                }
                Err(err) => {
                    assert_eq!(
                        result[3], "err",
                        "{name}/{step_name}: unexpected error {err:?}"
                    );
                    assert_eq!(
                        i64::from(err.code),
                        result[4].parse::<i64>().unwrap(),
                        "{name}/{step_name}: error code ({})",
                        err.message
                    );
                    assert_eq!(err.message, utf8(result[5]), "{name}/{step_name}: message");
                }
            }
        }
    }
    assert_eq!(scenarios, 19, "unexpected scenario count");
}
